  1969→```typescript
  1970→import chokidar from 'chokidar';
  1971→import fs from 'fs';
  1972→import { ClaudeCodeParser } from '@/parser';
  1973→import type { AnyBlock } from '@/types';
  1974→
  1975→export class SessionWatcher {
  1976→  private watcher: chokidar.FSWatcher | null = null;
  1977→  private parser = new ClaudeCodeParser();
  1978→  private lastPosition = 0;
  1979→  private filePath: string = '';
  1980→
  1981→  async watch(
  1982→    filePath: string,
  1983→    onBlocks: (blocks: AnyBlock[], isInitial: boolean) => void
  1984→  ): Promise<void> {
  1985→    this.filePath = filePath;
  1986→
  1987→    // Initial read
  1988→    const content = fs.readFileSync(filePath, 'utf-8');
  1989→    const blocks = this.parseContent(content);
  1990→    this.lastPosition = fs.statSync(filePath).size;
  1991→    onBlocks(blocks, true);
  1992→
  1993→    // Watch for changes
  1994→    this.watcher = chokidar.watch(filePath, {
  1995→      persistent: true,
  1996→      awaitWriteFinish: {
  1997→        stabilityThreshold: 100,
  1998→        pollInterval: 50,
  1999→      },
  2000→    });
  2001→
  2002→    this.watcher.on('change', () => {
  2003→      const newBlocks = this.readNewContent();
  2004→      if (newBlocks.length > 0) {
  2005→        onBlocks(newBlocks, false);
  2006→      }
  2007→    });
  2008→  }
  2009→
  2010→  private readNewContent(): AnyBlock[] {
  2011→    const stats = fs.statSync(this.filePath);
  2012→    if (stats.size <= this.lastPosition) {
  2013→      return [];
  2014→    }
  2015→
  2016→    const fd = fs.openSync(this.filePath, 'r');
  2017→    const newSize = stats.size - this.lastPosition;
  2018→    const buffer = Buffer.alloc(newSize);
  2019→    fs.readSync(fd, buffer, 0, newSize, this.lastPosition);
  2020→    fs.closeSync(fd);
  2021→
  2022→    this.lastPosition = stats.size;
  2023→
  2024→    const newContent = buffer.toString('utf-8');
  2025→    return this.parseContent(newContent);
  2026→  }
  2027→
  2028→  private parseContent(content: string): AnyBlock[] {
  2029→    const lines = content.trim().split('\n').filter(line => line.trim());
  2030→    const blocks: AnyBlock[] = [];
  2031→
  2032→    for (const line of lines) {
  2033→      const block = this.parser.parseLine(line);
  2034→      if (block) {
  2035→        blocks.push(block);
  2036→      }
  2037→    }
  2038→
  2039→    return blocks;
  2040→  }
  2041→
  2042→  stop(): void {
  2043→    if (this.watcher) {
  2044→      this.watcher.close();
  2045→      this.watcher = null;
  2046→    }
  2047→  }
  2048→}
  2049→```
