     3→/**
     4→ * Abstract base class for trace parsers
     5→ */
     6→export abstract class BaseParser implements TraceParser {
     7→  private blockIdCounter = 0;
     8→
     9→  abstract parse(content: string): ParsedSession;
    10→  abstract parseLine(line: string): AnyBlock | null;
    11→  abstract canParse(content: string): boolean;
    12→
    13→  /**
    14→   * Generate a unique block ID
    15→   */
    16→  generateBlockId(): string {
    17→    return `block-${++this.blockIdCounter}-${Date.now()}`;
    18→  }
    19→
    20→  /**
    21→   * Create a session object with default metadata
    22→   */
    23→  protected createSession(
    24→    filePath: string,
    25→    blocks: AnyBlock[],
    26→    chunks: Chunk[] = [],
