    30→      blocks.length > 0 ? Math.min(...blocks.map((b) => b.timestamp)) : Date.now();
    31→
    32→    const endTime =
    33→      blocks.length > 0 ? Math.max(...blocks.map((b) => b.timestamp)) : undefined;
    34→
    35→    return {
    36→      id: this.generateSessionId(filePath),
    37→      filePath,
    38→      blocks,
    39→      chunks,
    40→      metadata: {
    41→        startTime,
    42→        endTime,
    43→        ...metadata,
    44→      },
    45→    };
